10	export type RailFrame = {
11	  position: Vector3;
12	  tangent: Vector3;
13	  right: Vector3;
14	  up: Vector3;
15	};
16	
17	export function sampleRailFrame(curve: CatmullRomCurve3, u: number): RailFrame {
18	  const clamped = MathUtils.clamp(u, 0, 1);
19	  const position = curve.getPointAt(clamped);
20	  const tangent = curve.getTangentAt(clamped).normalize();
21	  const right = new Vector3().crossVectors(tangent, UP).normalize();
22	  if (right.lengthSq() < 0.0001) right.set(1, 0, 0);
23	  const up = new Vector3().crossVectors(right, tangent).normalize();
24	  return { position, tangent, right, up };
25	}
26	
27	export function offsetFromRail(curve: CatmullRomCurve3, u: number, offset: Vector3) {
28	  const frame = sampleRailFrame(curve, u);
29	  return frame.position
30	    .clone()
31	    .addScaledVector(frame.right, offset.x)
32	    .addScaledVector(frame.up, offset.y)
33	    .addScaledVector(frame.tangent, offset.z);
34	}
