11	export function colorForLockCount(
12	  lockCount: number,
13	  palette: readonly Color[] = DEFAULT_LOCK_GRADIENT,
14	  maxLocks = MAX_LOCKS,
15	) {
16	  if (palette.length === 0) return new Color(1, 1, 1);
17	  if (palette.length === 1 || maxLocks <= 1) return palette[0].clone();
18	
19	  const t = clamp01((lockCount - 1) / (maxLocks - 1));
20	  const scaled = t * (palette.length - 1);
21	  const lower = Math.floor(scaled);
22	  const upper = Math.min(palette.length - 1, lower + 1);
23	  return palette[lower].clone().lerp(palette[upper], scaled - lower);
24	}
25	
26	function clamp01(value: number) {
27	  return Math.min(1, Math.max(0, value));
