4	// Helios screen effects, driven per-frame by the runtime:
5	// - heat shimmer wobbles the frame while skimming the photosphere;
6	// - flash is the gold-white overload on drops and the supernova.
7	// Global motion blur is engine-owned in src/engine/post.ts.
8	export const heatUniform = uniform(0);
9	export const flashUniform = uniform(0);
10	
11	export function composeHeliosOutput({ base, scenePass, bloomPass, screenUV }: LevelPostComposeInput): LevelPostColorNode {
12	  const sceneTexture = scenePass.getTextureNode();
13	
14	  // Heat shimmer is a local distortion, not a motion-blur strength knob. Mix it
15	  // over the engine-composited frame so the normal path keeps global blur.
16	  const wobble = vec2(
17	    screenUV.y.mul(46).add(time.mul(8.2)).sin(),
18	    screenUV.x.mul(31).add(time.mul(6.1)).sin(),
19	  ).mul(heatUniform.mul(0.0038));
20	  const heatFrame = sceneTexture.sample(screenUV.add(wobble)).add(bloomPass);
21	  const color = mix(base, heatFrame, heatUniform.clamp(0, 0.65));
22	
23	  const flash = vec3(1.0, 0.84, 0.58).mul(flashUniform);
24	  return color.add(vec4(flash, float(0)));
25	}
